const raw = $input.first().json.output[0].content[0].text;
const cleaned = raw.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { intent: 'COMPLEX', order_number: null, confidence: 'low' };
}

// ─── Strip quoted/forwarded text from reply emails ───────────────────────
function stripQuotedText(text) {
  if (!text) return '';
  const separators = [
    /^>+\s.*/m,                           // Lines starting with >
    /^On .+wrote:/m,                       // Gmail: "On Mon, ... wrote:"
    /^Am .+schrieb .+:/m,                  // German: "Am Mo., ... schrieb:"
    /^-{3,}\s*Original Message\s*-{3,}/im, // "--- Original Message ---"
    /^-{3,}\s*Weitergeleitete Nachricht/im, // German forwarded header
    /^Von:\s+/m,                           // "Von:" quoted header
    /^From:\s+/m,                          // "From:" quoted header
  ];
  let clean = text;
  for (const sep of separators) {
    const idx = clean.search(sep);
    if (idx > 0) { clean = clean.substring(0, idx).trim(); break; }
  }
  return clean;
}

const fullBody = $('Edit Fields').first().json.body || '';
const cleanBody = stripQuotedText(fullBody); // Only parse the FRESH part of the email

// Extract order number from clean body only (not quoted thread)
const bodyOrderMatch = 
  cleanBody.match(/BESTELLNUMMER[:\s]+(\d+)/i) ||
  cleanBody.match(/Bestellung(?:snummer)?[:\s#]+(\d+)/i) ||
  cleanBody.match(/^(\d{4,6})\s*$/m);

const orderNumber = parsed.order_number || (bodyOrderMatch ? bodyOrderMatch[1] : null);

// Force ORDER_TRACKING if a BESTELLNUMMER pattern found in fresh body
const intent = (bodyOrderMatch && !parsed.order_number)
  ? 'ORDER_TRACKING'
  : (parsed.intent || 'COMPLEX');

// Clean sender email
const senderRaw = $('Edit Fields').first().json.sender_email || '';
const senderClean = senderRaw.replace(/^=+/, '').trim();
const senderMatch = senderClean.match(/<([^>]+)>/);
const senderEmail = senderMatch ? senderMatch[1].trim() : senderClean;

return [{
  json: {
    intent,
    order_number: orderNumber,
    confidence: parsed.confidence || 'low',
    sender_email: senderEmail,
    subject: $('Edit Fields').first().json.subject,
    body: fullBody,
    clean_body: cleanBody,
    date_received: $('Edit Fields').first().json.date_received
  }
}];

const order = $input.first().json;

if (!order || !order.id) {
  return [{
    json: {
      found: false,
      sender_email: $('Edit Fields').first().json.sender_email,
      subject: $('Edit Fields').first().json.subject
    }
  }];
}

const shipment = order.shipments?.[0] || null;

const statusMap = {
  'pending':    'Deine Zahlung steht noch aus.',
  'processing': 'Deine Bestellung wird gerade bearbeitet.',
  'on-hold':    'Deine Bestellung wartet auf Bestaetigung.',
  'completed':  'Deine Bestellung wurde versandt.',
  'cancelled':  'Deine Bestellung wurde leider storniert.',
  'refunded':   'Deine Bestellung wurde erstattet.',
  'failed':     'Die Zahlung ist leider fehlgeschlagen.'
};

return [{
  json: {
    found:           true,
    order_id:        order.id,
    order_number:    order.number || order.id,
    customer_name:   order.billing?.first_name || 'Kunde',
    status_german:   statusMap[order.status] || 'Status unbekannt.',
    shipping_method: order.shipping_lines?.[0]?.method_title || null,
    items:           order.line_items?.map(i => i.name).join(', ') || null,
    tracking_id:     shipment?.tracking_id || null,
    tracking_url:    shipment?.tracking_url || null,
    carrier:         shipment?.shipping_provider_title || null,
    sender_email:    $('Edit Fields').first().json.sender_email,
    subject:         $('Edit Fields').first().json.subject
  }
}];

