const order = $input.first().json;

// WooCommerce date_created fix
let orderDate;
try {
  const raw = order.date_created || order.date_created_gmt;
  // WooCommerce format: "2026-05-06T10:30:00"
  orderDate = new Date(raw.replace(' ', 'T'));
  if (isNaN(orderDate.getTime())) throw new Error('Invalid');
} catch(e) {
  // fallback to current date if parsing fails
  orderDate = new Date();
}

const now = new Date();

function countWorkingDays(startDate, endDate) {
  let count = 0;
  const current = new Date(startDate);
  current.setHours(0, 0, 0, 0);
  const end = new Date(endDate);
  end.setHours(0, 0, 0, 0);
  while (current < end) {
    const day = current.getDay();
    if (day !== 0 && day !== 6) count++;
    current.setDate(current.getDate() + 1);
  }
  return count;
}

function addWorkingDays(startDate, days) {
  const date = new Date(startDate);
  let added = 0;
  while (added < days) {
    date.setDate(date.getDate() + 1);
    const day = date.getDay();
    if (day !== 0 && day !== 6) added++;
  }
  return date;
}

const formatDate = (date) => date.toLocaleDateString('de-DE', {
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

const workingDaysSinceOrder = countWorkingDays(orderDate, now);
const estimatedEarly = addWorkingDays(orderDate, 3);
const estimatedLate = addWorkingDays(orderDate, 5);
const isSameDay = workingDaysSinceOrder === 0;
const tooEarly = workingDaysSinceOrder < 3;

return [{
  json: {
    ...order,
    working_days_since_order: workingDaysSinceOrder,
    too_early: tooEarly,
    is_same_day: isSameDay,
    order_date: formatDate(orderDate),
    estimated_dispatch: formatDate(estimatedEarly) + ' bis ' + formatDate(estimatedLate)
  }
}];

const data = $input.first().json;
const orders = Array.isArray(data) ? data : [data];

const senderEmail = $('Edit Fields').first().json.sender_email;
const cleanSender = (senderEmail || '').toLowerCase().trim().replace(/[<>]/g, '');

// Filter orders that match the email
const matchingOrders = orders.filter(o => 
  (o?.billing?.email || '').toLowerCase().trim() === cleanSender
);

if (!matchingOrders || matchingOrders.length === 0) {
  return [{
    json: {
      found: false,
      sender_email: senderEmail,
      subject: $('Edit Fields').first().json.subject
    }
  }];
}

// Use most recent order by default
const order = matchingOrders[0];

return [{
  json: {
    found: true,
    order_id: order.id,
    total_orders: matchingOrders.length,
    sender_email: senderEmail,
    subject: $('Edit Fields').first().json.subject
  }
}];
